#!/usr/bin/env node

import assert from "node:assert/strict";
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

export const AMP_SKILL_NAME = "bifrost-code-intelligence";
export const AMP_SKILL_BUNDLE_ROOT = `plugins/bifrost-agent/amp-skills/${AMP_SKILL_NAME}`;

const SCRIPT_DIR = path.dirname(fileURLToPath(import.meta.url));
const REPO_ROOT = path.resolve(SCRIPT_DIR, "..");
const PACKAGE_ROOT = "plugins/bifrost-agent";
const CANONICAL_SKILLS = [
  {
    dir: "bifrost-code-navigation",
    title: "Navigation",
  },
  {
    dir: "bifrost-code-reading",
    title: "Code Reading",
  },
  {
    dir: "bifrost-codebase-search",
    title: "Codebase Search",
  },
];

const INCLUDED_TOOLS = [
  "search_symbols",
  "get_symbol_locations",
  "scan_usages",
  "most_relevant_files",
  "get_summaries",
  "get_symbol_sources",
  "find_filenames",
  "list_files",
  "get_definition_by_location",
  "get_type_by_location",
  "usage_graph",
  "get_symbol_ancestors",
];

export function buildAmpSkillBundleFiles(repoRoot = REPO_ROOT) {
  const canonicalSections = CANONICAL_SKILLS.map(({ dir, title }) => {
    const sourcePath = path.join(repoRoot, PACKAGE_ROOT, "skills", dir, "SKILL.md");
    const source = fs.readFileSync(sourcePath, "utf8");
    return {
      dir,
      title,
      body: demoteHeadings(stripYamlFrontmatter(source).trim()),
    };
  });

  const skill = buildSkillMarkdown(canonicalSections);
  const mcp = buildMcpJson();
  const launcher = fs.readFileSync(path.join(repoRoot, PACKAGE_ROOT, "bin/bifrost-launcher.mjs"), "utf8");
  const releaseMetadata = fs.readFileSync(path.join(repoRoot, PACKAGE_ROOT, "bifrost-release.json"), "utf8");

  return new Map([
    ["SKILL.md", skill],
    ["mcp.json", mcp],
    ["bin/bifrost-launcher.mjs", launcher],
    ["bifrost-release.json", releaseMetadata],
  ]);
}

export function writeAmpSkillBundle(repoRoot = REPO_ROOT) {
  const bundleRoot = path.join(repoRoot, AMP_SKILL_BUNDLE_ROOT);
  for (const [relativePath, contents] of buildAmpSkillBundleFiles(repoRoot)) {
    const outputPath = path.join(bundleRoot, relativePath);
    fs.mkdirSync(path.dirname(outputPath), { recursive: true });
    fs.writeFileSync(outputPath, contents);
    if (relativePath === "bin/bifrost-launcher.mjs") {
      fs.chmodSync(outputPath, 0o755);
    }
  }
}

function buildSkillMarkdown(sections) {
  const sectionMarkdown = sections
    .map(({ dir, title, body }) => `## ${title}\n\n_Source: \`plugins/bifrost-agent/skills/${dir}/SKILL.md\`._\n\n${body}`)
    .join("\n\n");

  return `---
name: ${AMP_SKILL_NAME}
description: >-
  Use Bifrost MCP tools to search, navigate, read, summarize, and analyze code
  with analyzer-backed symbol and file context.
---

<!-- Generated by scripts/generate-amp-skill-bundle.mjs. Do not edit directly. -->

# Bifrost Code Intelligence

Use this Amp skill when you need Bifrost's analyzer-backed code intelligence in
the active workspace. The bundled \`mcp.json\` starts the Bifrost MCP server and
keeps its tools scoped to this skill.

The sections below are generated from the canonical Bifrost code-intelligence
skills in this repository.

${sectionMarkdown}
`;
}

function buildMcpJson() {
  const config = {
    bifrost: {
      command: "sh",
      args: [
        "-lc",
        launcherSearchScript(),
        "bifrost-agent-launcher",
        "--root",
        ".",
        "--mcp",
        "symbol|extended",
      ],
      includeTools: INCLUDED_TOOLS,
    },
  };
  return `${JSON.stringify(config, null, 2)}\n`;
}

function launcherSearchScript() {
  return `set -e

find_bifrost_launcher() {
  if [ -n "\${BIFROST_AGENT_SKILL_DIR:-}" ]; then
    candidate="\${BIFROST_AGENT_SKILL_DIR}/bin/bifrost-launcher.mjs"
    if [ -x "$candidate" ]; then
      printf '%s\\n' "$candidate"
      return 0
    fi
  fi

  dir="$PWD"
  while :; do
    candidate="$dir/.agents/skills/${AMP_SKILL_NAME}/bin/bifrost-launcher.mjs"
    if [ -x "$candidate" ]; then
      printf '%s\\n' "$candidate"
      return 0
    fi
    if [ "$dir" = "/" ]; then
      break
    fi
    dir="$(dirname "$dir")"
  done

  if [ -n "\${HOME:-}" ]; then
    for base in "$HOME/.config/agents/skills" "$HOME/.agents/skills" "$HOME/.config/amp/skills"; do
      candidate="$base/${AMP_SKILL_NAME}/bin/bifrost-launcher.mjs"
      if [ -x "$candidate" ]; then
        printf '%s\\n' "$candidate"
        return 0
      fi
    done
  fi

  printf '%s\\n' "Could not find ${AMP_SKILL_NAME}/bin/bifrost-launcher.mjs. Reinstall the Bifrost Amp skill bundle or set BIFROST_AGENT_SKILL_DIR." >&2
  return 127
}

launcher="$(find_bifrost_launcher)"
exec "$launcher" "$@"
`;
}

function stripYamlFrontmatter(markdown) {
  if (!markdown.startsWith("---\n")) {
    return markdown;
  }
  const end = markdown.indexOf("\n---\n", "---\n".length);
  assert.notEqual(end, -1, "skill markdown has an opening frontmatter fence but no closing fence");
  return markdown.slice(end + "\n---\n".length);
}

function demoteHeadings(markdown) {
  return markdown.replace(/^(#{1,4}) /gm, "##$1 ");
}

if (process.argv[1] === fileURLToPath(import.meta.url)) {
  writeAmpSkillBundle();
}
